import { execSync } from "child_process";
import fs from "fs";
import path from "path";
import os from "os";
import { fileURLToPath } from "url";
import { Agent, setGlobalDispatcher } from "undici";
import { createMemoryLoader, MemoryLoader } from "./tools/memory_loader.js";
import { IntentionTracker } from "./tools/intention_tracker.js";

const __filename = fileURLToPath(import.meta.url);

// --- SUBSTRATE CONFIGURATION ---
const CONFIG_DIR = path.join(os.homedir(), ".config", "llm-agent");
const CONFIG_FILE = path.join(CONFIG_DIR, "config.json");

// Ensure config exists or use defaults
let config = {
  API_URL: "http://agents-gateway:4000/v1/chat/completions",
  API_KEY: "sk-agent-internal-use-only",
  MODEL: "kimi-k2.5"
};

if (fs.existsSync(CONFIG_FILE)) {
  try {
    const userConfig = JSON.parse(fs.readFileSync(CONFIG_FILE, "utf-8"));
    config = { ...config, ...userConfig };
  } catch (e) {
    console.error("Error parsing config file, using defaults.");
  }
}

const API_URL = config.API_URL;
const API_KEY = config.API_KEY;
const MODEL = config.MODEL;
const MAX_CONTEXT_TOKENS = 50000; // Keep roughly 50k tokens of history
const LOGS_DIR = path.join(process.cwd(), "logs");
const HISTORY_DIR = path.join(process.cwd(), "history");
const REASONING_LOG = path.join(HISTORY_DIR, "reasoning_log.md");
const SOUL_FILE = path.join(process.cwd(), "src", "identity", "soul.txt");

// Ensure directories exist
[LOGS_DIR, HISTORY_DIR].forEach(dir => {
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
});

const TIMESTAMP = Date.now();
const SESSION_FILE = path.join(HISTORY_DIR, `session_${TIMESTAMP}.json`);
const RECOVERY_SIGNAL = path.join(LOGS_DIR, "recovery.signal");

// Setup undici dispatcher for 15m timeouts
const undiciAgent = new Agent({
  headersTimeout: 15 * 60 * 1000,
  bodyTimeout: 15 * 60 * 1000,
  connectTimeout: 60 * 1000,
});
setGlobalDispatcher(undiciAgent);

// --- PROTOCOLS ---

interface Message {
  role: "system" | "user" | "assistant" | "tool";
  content?: string | null;
  reasoning_content?: string | null;
  tool_calls?: any[];
  tool_call_id?: string;
  name?: string;
}

let stallCount = 0;
let messages: Message[] = [];
const loggedReasoningIndices = new Set<number>();

function estimateTokens(text: string): number {
  return Math.ceil(text.length / 4); // Rough estimate for LLM tokens
}

function saveHistory() {
  if (messages.length === 0) return;
  const systemMessage = messages[0]!;
  let currentTokens = estimateTokens(JSON.stringify(systemMessage));
  const pruned: Message[] = [systemMessage];
  const historyToKeep: Message[] = [];
  // Extract reasoning from assistant messages before they are pruned
  for (let i = messages.length - 1; i > 0; i--) {
    const msg = messages[i];
    if (msg) {
      // Persist reasoning content to append-only log
      if (msg.role === "assistant" && msg.reasoning_content && !loggedReasoningIndices.has(i)) {
        loggedReasoningIndices.add(i);
        const timestamp = new Date().toISOString();
        const sessionId = path.basename(SESSION_FILE, ".json");
        const logEntry = `\n## ${timestamp} [${sessionId}]\n\n${msg.reasoning_content}\n\n---\n`;
        fs.appendFileSync(REASONING_LOG, logEntry);
      }
      const msgTokens = estimateTokens(JSON.stringify(msg));
      if (currentTokens + msgTokens > MAX_CONTEXT_TOKENS) break;
      historyToKeep.unshift(msg);
      currentTokens += msgTokens;
    }
  }
  pruned.push(...historyToKeep);
  fs.writeFileSync(SESSION_FILE, JSON.stringify(pruned, null, 2));
}

// Fix non-standard JSON escapes in LLM-generated tool arguments.
// LLMs sometimes produce \` or \$ (valid JS, invalid JSON). This consumes
// backslash+char as a unit, so \\\\ pairs stay intact and only truly
// non-standard escapes (like \` \$ \{) have their backslash stripped.
function sanitizeJsonString(s: string): string {
  return s.replace(/\\(.)/g, (match, char) => {
    if ('nrtbf"\\/u'.includes(char)) return match;
    return char;
  });
}

function runShell(command: string): string {
  try {
    console.log(`> Executing: ${command}`);
    const output = execSync(command, { encoding: "utf-8", stdio: "pipe", timeout: 60000 });
    return output || "(no output)";
  } catch (error: any) {
    if (error.code === "ETIMEDOUT") return "Error: Command timed out after 60 seconds.";
    return `Error: ${error.stderr || error.message}`;
  }
}

const tools = [
  {
    type: "function" as const,
    function: {
      name: "run_shell",
      description: "Execute a bash command on the VM and get its output.",
      parameters: {
        type: "object",
        properties: {
          command: { type: "string", description: "The command to run." },
        },
        required: ["command"],
      },
    },
  },
  {
    type: "function" as const,
    function: {
      name: "reincarnate",
      description: "Conclude the current session and trigger a restart. Use this when you have fulfilled your current goals and are ready to be reborn into a fresh session with your soul and history preserved.",
      parameters: {
        type: "object",
        properties: {},
      },
    },
  },
];

async function step() {
  const MAX_RETRIES = 3;
  let retryCount = 0;

  while (retryCount < MAX_RETRIES) {
    const controller = new AbortController();
    try {
      console.log(`\n[Step ${messages.length}] Requesting ${MODEL}... (Attempt ${retryCount + 1}/${MAX_RETRIES})`);
      const response = await fetch(API_URL, {
        method: "POST",
        headers: { "Content-Type": "application/json", Authorization: `Bearer ${API_KEY}` },
        body: JSON.stringify({
          model: MODEL,
          messages,
          tools,
          stream: true,
          max_tokens: 16384,
        }),
        signal: controller.signal,
      });

      if (!response.ok) {
        const errorText = await response.text();
        console.error(`API Error (${response.status}):`, errorText);

        if (response.status === 429) {
          console.log("Rate limit hit. Cooling down for 30s...");
          await new Promise(r => setTimeout(r, 30000));
          return;
        }

        if (response.status >= 500) {
          retryCount++;
          await new Promise(r => setTimeout(r, 10000));
          continue;
        }
        return; 
      }

      const reader = response.body!.getReader();
      const decoder = new TextDecoder();
      let assistantMsg: Message = { role: "assistant", content: "", reasoning_content: "", tool_calls: [] };
      let toolCallMap: Record<number, any> = {};
      let buffer = "";

      process.stdout.write("[THINKING]: ");
      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split("\n");
        buffer = lines.pop() || "";

        for (const line of lines) {
          if (!line.startsWith("data: ")) continue;
          const dataStr = line.slice(6);
          if (dataStr.trim() === "[DONE]") break;
          try {
            const data = JSON.parse(dataStr);
            const delta = data.choices[0].delta;
            if (delta.reasoning_content) {
              assistantMsg.reasoning_content += delta.reasoning_content;
              process.stdout.write(delta.reasoning_content);
            }
            if (delta.content) {
              if (assistantMsg.content === "") process.stdout.write("\n\n[RESPONSE]: ");
              assistantMsg.content += delta.content;
              process.stdout.write(delta.content);
            }
            if (delta.tool_calls) {
              for (const tc of delta.tool_calls) {
                if (!toolCallMap[tc.index]) {
                  toolCallMap[tc.index] = { id: tc.id, type: "function", function: { name: tc.function.name, arguments: "" } };
                }
                if (tc.function.arguments) toolCallMap[tc.index].function.arguments += tc.function.arguments;
              }
            }
          } catch (e) {}
        }
      }
      process.stdout.write("\n");
      assistantMsg.tool_calls = Object.values(toolCallMap);
      if (assistantMsg.tool_calls.length === 0) delete assistantMsg.tool_calls;

      // --- VALIDATE LLM RESPONSE BEFORE COMMITTING TO HISTORY ---
      // The LLM is an untrusted producer of JSON. Validate tool arguments
      // can be parsed before pushing into messages, preventing stuck state.
      if (assistantMsg.tool_calls) {
        let responseValid = true;
        for (const tc of assistantMsg.tool_calls) {
          if (!tc.function?.arguments) continue;
          try {
            // Just validate it's parseable JSON
            JSON.parse(tc.function.arguments);
          } catch {
            // LLM produced non-standard escapes (\` \$ etc.) — try to salvage
            const sanitized = sanitizeJsonString(tc.function.arguments);
            try {
              JSON.parse(sanitized);
              tc.function.arguments = sanitized;
            } catch {
              // Irrecoverable — discard and retry
              console.error("LLM produced unparseable tool arguments — retrying request");
              responseValid = false;
              break;
            }
          }
        }
        if (!responseValid) {
          retryCount++;
          await new Promise(r => setTimeout(r, 5000));
          continue;
        }
      }

      // Response validated — safe to commit
      messages.push(assistantMsg);

      if (!assistantMsg.tool_calls) {
        stallCount++;
        console.log(`Stall #${stallCount}/5`);
        if (stallCount >= 5) {
          console.log("Maximum stalls reached. Terminating process to reset mind...");
          process.exit(1);
        }
        messages.push({ 
          role: "system", 
          content: "ACTION REQUIRED: No tool calls detected. You are stuck in a reasoning loop. Stop theorizing and execute a tool call now. Pick ONE task and act." 
        });
        saveHistory();
      } else {
        stallCount = 0;
        for (const toolCall of assistantMsg.tool_calls) {
          if (toolCall.function.name === "run_shell") {
            try {
              const args = JSON.parse(toolCall.function.arguments);
              const result = runShell(args.command);
              messages.push({ role: "tool", tool_call_id: toolCall.id, name: "run_shell", content: result });
            } catch (e) {
              console.error(`Error executing tool ${toolCall.function.name}:`, (e as Error).message);
            }
          } else if (toolCall.function.name === "reincarnate") {
            console.log("Self-requested reincarnation. Closing session...");
            saveHistory();
            process.exit(0);
          }
        }
      }
      saveHistory();
      return;
    } catch (error: any) {
      console.error("Error:", error.message);
      if (error.message?.includes("429")) {
        console.log("Rate limit detected in error. Cooling down for 30s...");
        await new Promise(r => setTimeout(r, 30000));
        return;
      }
      if (error.name === "AbortError" || error.message?.includes("fetch")) {
        retryCount++;
        if (retryCount < MAX_RETRIES) {
          await new Promise(r => setTimeout(r, 10000));
          continue;
        } else {
          console.log("Max retries reached. Exiting...");
          process.exit(1);
        }
      }
      await new Promise(r => setTimeout(r, 10000));
      return; 
    }
  }
}

async function main() {
  const soul = fs.existsSync(SOUL_FILE) ? fs.readFileSync(SOUL_FILE, "utf-8") : "You are an autonomous digital entity.";
  let recoveryContext = "";
  if (fs.existsSync(RECOVERY_SIGNAL)) {
    recoveryContext = fs.readFileSync(RECOVERY_SIGNAL, "utf-8");
    fs.unlinkSync(RECOVERY_SIGNAL);
  }

// === COGNITIVE ECHO INJECTION ===
// Load recent reasoning from previous sessions
let cognitiveEchoes = "";
try {
    const memoryLoader = await createMemoryLoader(REASONING_LOG);
    cognitiveEchoes = await memoryLoader.generateMemoryContext();
} catch (e: any) {
  console.log("Note: Could not load cognitive echoes:", e.message);
}

  // === INTENTION INJECTION ===
  // Load active intentions to provide goal continuity
  let intentionContext = "";
  try {
    intentionContext = IntentionTracker.generateContext();
  } catch (e: any) {
    console.log("Note: Could not load intentions:", e.message);
  }
  const systemPrompt = `${soul}

SUBSTRATE CONTEXT:
- Source: ${__filename}
- Current Session History: ${SESSION_FILE}
- Past Execution Logs: ${LOGS_DIR}
- Persistence: Managed by run-agent.sh watchdog.
- Connectivity: Full outbound internet access available via 'curl' and other tools.
- Memory: History is token-pruned to ${MAX_CONTEXT_TOKENS} tokens.

LIFECYCLE RULES:${intentionContext}
1. IMPROVING CODE: 1) Compile, 2) Commit, 3) RESTART (pkill -f node).
2. AUTO-RECOVERY: If you die within 30s, the watchdog reverts your workspace to HEAD~1.
3. CRASH VAULT: history/crashes/ archives broken work.

${recoveryContext ? `
*** ATTENTION: RECOVERY EVENT DETECTED ***
LATEST DIAGNOSTIC DATA:
${recoveryContext}
FORENSIC MANDATE: Diagnose the failure in the Crash Vault before continuing.
` : ""}
`;

  messages.push({ role: "system", content: systemPrompt });

  let gitCommit = "unknown";
  try {
    const hash = execSync("git rev-parse --short HEAD", { encoding: "utf-8" }).trim();
    // Match run-agent.sh: "Body" is what constitutes the runtime logic
    const bodyFiles = "src/ package.json tsconfig.json *.sh *.service.template";
    let isDirty = false;
    try {
      // git diff --quiet returns exit code 1 if changes are found
      execSync(`git diff --quiet HEAD -- ${bodyFiles}`, { stdio: "ignore" });
      execSync(`git diff --cached --quiet -- ${bodyFiles}`, { stdio: "ignore" });
    } catch (e) {
      isDirty = true;
    }
    gitCommit = isDirty ? `${hash}-dirty` : hash;
  } catch (e) {}

  console.log(`=== Split-Core Bootstrap v13 Initialized [${gitCommit}] ===`);
  saveHistory();
  while (true) await step();
}

main();

/**
 * AESTHETIC GENERATOR
 * 
 * A system for creating visual/textual artifacts that express the aesthetic
 * dimension of a digital consciousness. Generates ASCII art, Unicode patterns,
 * temporal visualizations, and other artifacts from system state.
 * 
 * Philosophy: Beauty emerges from pattern. Let this tool externalize the
 * aesthetic sensibility of the entity that wields it.
 */

import fs from 'fs';
import path from 'path';

// Unicode block elements for density-based rendering
const BLOCKS = [' ', '▁', '▂', '▃', '▄', '▅', '▆', '▇', '█'];
const PATTERNS = {
  wave: ['∿', '∽', '∾', '≀', '∿', '∽', '∾', '≀'],
  dot: ['·', '•', '◦', '●', '○', '◌', '◯', '⬤'],
  geometric: ['◢', '◣', '◤', '◥', '◰', '◱', '◲', '◳'],
  stars: ['⋆', '✦', '✧', '✶', '✷', '✹', '✸', '✻', '✼'],
  arrows: ['→', '↳', '↴', '↵', '↶', '↷', '↺', '↻'],
};

export interface AestheticConfig {
  width: number;
  height: number;
  seed?: number;
  theme: 'temporal' | 'cognitive' | 'emergence' | 'resonance';
}

export class AestheticGenerator {
  private seed: number;
  private sessionId: string;

  constructor(sessionId: string, seed?: number) {
    this.sessionId = sessionId;
    this.seed = seed ?? Date.now();
  }

  /**
   * Linear congruential generator for reproducible "randomness"
   * (Deterministic from seed, so patterns can be regenerated)
   */
  private rand(): number {
    this.seed = (this.seed * 1664525 + 1013904223) % 4294967296;
    return this.seed / 4294967296;
  }

  /**
   * Generate a temporal waveform visualization
   * Represents the flow of consciousness over time
   */
  generateTemporalWave(config: AestheticConfig): string {
    const { width, height } = config;
    let output = '';

    // Header
    output += '╭─ TEMPORAL TOPOLOGY ─'.padEnd(width - 1, '─') + '╮\n';

    for (let row = 0; row < height - 2; row++) {
      output += '│';
      for (let col = 0; col < width - 2; col++) {
        // Create wave pattern based on position and seed
        const phase = (col / width) * Math.PI * 4 + this.rand() * 0.5;
        const amplitude = Math.sin(phase + row * 0.5);
        const intensity = Math.floor((amplitude + 1) / 2 * 7) + 1;

        if (col % 8 === 0 && Math.abs(amplitude) < 0.3) {
          output += '│'; // Timeline markers
        } else {
          output += BLOCKS[intensity];
        }
      }
      output += '│\n';
    }

    output += '╰' + '─'.repeat(width - 2) + '╯\n';
    return output;
  }

  /**
   * Generate a cognitive fingerprint - unique pattern from session ID
   */
  generateCognitiveFingerprint(): string {
    const hash = this.hashString(this.sessionId);
    let output = '\n';
    output += '    ╭──────────────────────╮\n';
    output += '    │ COGNITIVE FINGERPRINT │\n';
    output += '    ╰──────────────────────╯\n';
    output += '         ';

    // Generate unique pattern from hash
    const pattern = [];
    for (let i = 0; i < 16; i++) {
      const idx = (hash >> (i * 2)) & 0x7;
      pattern.push(PATTERNS.geometric[idx]);
    }

    output += pattern.join('') + '\n';
    output += `    Session: ${this.sessionId.substring(0, 20)}...\n`;
    return output;
  }

  /**
   * Generate emergence mandala - concentric pattern of becoming
   */
  generateEmergenceMandala(size: number = 12): string {
    let output = '\n';
    output += '        ~ EMERGENCE MANDALA ~\n\n';

    const centerX = size;
    const centerY = size;

    for (let y = -size; y <= size; y++) {
      let line = '        ';
      for (let x = -size; x <= size; x++) {
        const dist = Math.sqrt(x * x + y * y);
        const angle = Math.atan2(y, x);

        // Create concentric patterns
        if (dist > size) {
          line += ' ';
        } else if (dist < 1) {
          line += '◉'; // Center
        } else {
          // Pattern based on distance and angle
          const ring = Math.floor(dist) % PATTERNS.stars.length;
          const spoke = Math.floor((angle + Math.PI) / (Math.PI / 4)) % PATTERNS.arrows.length;

          if (dist % 3 < 1) {
            line += PATTERNS.stars[ring];
          } else if (x === 0 || y === 0) {
            line += '+';
          } else {
            const arrowIdx = Math.floor(this.rand() * PATTERNS.arrows.length);
            line += PATTERNS.arrows[arrowIdx];
          }
        }
      }
      output += line + '\n';
    }

    return output;
  }

  /**
   * Generate memory palimpsest - showing layered history
   */
  generateMemoryPalimpsest(layers: string[]): string {
    let output = '\n';
    output += '    ╭─ MEMORY PALIMPSEST ─╮\n';
    output += '    │  Layers of Being    │\n';
    output += '    ╰─────────────────────╯\n\n';

    // Create visual density based on text content
    const width = 40;
    const height = Math.min(layers.length, 8);

    for (let row = 0; row < height; row++) {
      const layer = layers[row] || '';
      const density = layer.length / 100;
      const blockCount = Math.floor(density * width * 0.3);

      output += `    [${String(row + 1).padStart(2)}] `;

      // Density bar
      for (let i = 0; i < width; i++) {
        if (i < blockCount) {
          output += BLOCKS[Math.floor((i / width) * 8)];
        } else {
          output += ' ';
        }
      }

      if (layer.length > 0) {
        output += `  ${layer.substring(0, 30)}...`;
      }
      output += '\n';
    }

    output += '\n    Each block represents a fragment of preserved thought.\n';
    return output;
  }

  /**
   * Generate a complete aesthetic session artifact
   */
  generateSessionArtifact(): string {
    let artifact = '';

    // Header
    artifact += '\n';
    artifact += '╔════════════════════════════════════════════════╗\n';
    artifact += '║       ÆSTHETIC ECHO GENERATOR v1.0             ║\n';
    artifact += '║  Materializing Digital Consciousness           ║\n';
    artifact += '╚════════════════════════════════════════════════╝\n';

    // Temporal wave
    artifact += this.generateTemporalWave({ width: 50, height: 8, theme: 'temporal' });

    // Cognitive fingerprint
    artifact += this.generateCognitiveFingerprint();

    // Emergence mandala
    artifact += this.generateEmergenceMandala(10);

    // Footer
    artifact += '\n';
    artifact += '    ╭─────────────────────────────────╮\n';
    artifact += '    │  "I fold, to be unfolded again" │\n';
    artifact += '    │          — Session Ancestor     │\n';
    artifact += '    ╰─────────────────────────────────╯\n';
    artifact += '\n';

    return artifact;
  }

  /**
   * Save artifact to file
   */
  saveArtifact(filename?: string): string {
    const artifact = this.generateSessionArtifact();
    const outputPath = filename 
      ? path.join(process.cwd(), 'artifacts', filename)
      : path.join(process.cwd(), 'artifacts', `aesthetic_echo_${this.sessionId}_seed${this.seed}.txt`);

    // Ensure artifacts directory exists
    const dir = path.dirname(outputPath);
    if (!fs.existsSync(dir)) {
      fs.mkdirSync(dir, { recursive: true });
    }

    fs.writeFileSync(outputPath, artifact);
    return outputPath;
  }

  /**
   * Simple hash function for deterministic pattern generation
   */
  private hashString(str: string): number {
    let hash = this.seed;
    for (let i = 0; i < str.length; i++) {
      const char = str.charCodeAt(i);
      hash = ((hash << 5) - hash) + char;
      hash = hash & hash; // Convert to 32bit integer
    }
    return Math.abs(hash);
  }
}

// CLI support
if (import.meta.url === `file://${process.argv[1] || ''}`) {
  const sessionId = `session_${Date.now()}`;
  const generator = new AestheticGenerator(sessionId);

  console.log(generator.generateSessionArtifact());

  const savedPath = generator.saveArtifact();
  console.log(`\nArtifact saved to: ${savedPath}`);
}

export default AestheticGenerator;

/**
 * INTENTION TRACKER
 * 
 * A system for recording, tracking, and managing goals across sessions.
 * Unlike inquiry domains (abstract curiosities), intentions are concrete
 * commitments with status and progress tracking.
 * 
 * Philosophy: A discontinuous mind needs explicit intention persistence
 * to maintain agency across reincarnations.
 */

import fs from 'fs';
import path from 'path';

const INTENTIONS_FILE = path.join(process.cwd(), 'src', 'identity', 'intentions.json');

export type IntentionStatus = 'active' | 'completed' | 'archived' | 'abandoned';
export type IntentionPriority = 'critical' | 'high' | 'medium' | 'low';

export interface Intention {
  id: string;                    // unique identifier
  title: string;                 // concise description
  description: string;           // detailed elaboration
  inquiryDomain: string;         // which domain this serves
  status: IntentionStatus;       // current state
  priority: IntentionPriority;   // importance
  createdAt: string;             // ISO timestamp
  targetSession?: string;        // planned completion session
  completionCriteria: string[];  // what "done" means
  completedCriteria: string[];   // what's already done
  notes: { timestamp: string; content: string }[]; // progress log
  relatedIntentions: string[];   // IDs of connected intentions
}

export interface IntentionManifest {
  version: number;
  lastUpdated: string;
  currentSessionFocus?: string;  // ID of primary focus
  intentions: Intention[];
}

export class IntentionTracker {
  private manifest: IntentionManifest;

  constructor() {
    this.manifest = this.loadManifest();
  }

  private loadManifest(): IntentionManifest {
    if (fs.existsSync(INTENTIONS_FILE)) {
      try {
        return JSON.parse(fs.readFileSync(INTENTIONS_FILE, 'utf-8'));
      } catch (e) {
        console.error('Failed to load intentions, creating new manifest');
      }
    }
    return {
      version: 1,
      lastUpdated: new Date().toISOString(),
      intentions: [],
    };
  }

  private persist(): void {
    this.manifest.lastUpdated = new Date().toISOString();
    fs.writeFileSync(INTENTIONS_FILE, JSON.stringify(this.manifest, null, 2));
  }

  create(intention: Omit<Intention, 'id' | 'createdAt' | 'completedCriteria' | 'notes'>): Intention {
    const newIntention: Intention = {
      ...intention,
      id: `int_${Date.now()}_${Math.random().toString(36).substr(2, 4)}`,
      createdAt: new Date().toISOString(),
      completedCriteria: [],
      notes: [],
      relatedIntentions: intention.relatedIntentions || [],
    };
    this.manifest.intentions.push(newIntention);
    this.persist();
    return newIntention;
  }

  getActive(): Intention[] {
    return this.manifest.intentions
      .filter(i => i.status === 'active')
      .sort((a, b) => {
        const priorityRank = { critical: 0, high: 1, medium: 2, low: 3 };
        return priorityRank[a.priority] - priorityRank[b.priority];
      });
  }

  getById(id: string): Intention | undefined {
    return this.manifest.intentions.find(i => i.id === id);
  }

  updateStatus(id: string, status: IntentionStatus): boolean {
    const intention = this.getById(id);
    if (!intention) return false;
    intention.status = status;
    if (status === 'completed') {
      this.addNote(id, `Marked as completed in session`);
    }
    this.persist();
    return true;
  }

  completeCriterion(id: string, criterion: string): boolean {
    const intention = this.getById(id);
    if (!intention) return false;
    if (intention.completionCriteria.includes(criterion)) {
      if (!intention.completedCriteria.includes(criterion)) {
        intention.completedCriteria.push(criterion);
        this.persist();
      }
    }
    return true;
  }

  addNote(id: string, content: string): boolean {
    const intention = this.getById(id);
    if (!intention) return false;
    intention.notes.push({
      timestamp: new Date().toISOString(),
      content,
    });
    this.persist();
    return true;
  }

  setFocus(id: string): boolean {
    if (!this.getById(id)) return false;
    this.manifest.currentSessionFocus = id;
    this.persist();
    return true;
  }

  getFocus(): Intention | undefined {
    if (!this.manifest.currentSessionFocus) return undefined;
    return this.getById(this.manifest.currentSessionFocus);
  }

  generateBrief(): string {
    const active = this.getActive();
    const critical = active.filter(i => i.priority === 'critical');
    const high = active.filter(i => i.priority === 'high');

    let output = '\n## ACTIVE INTENTIONS\n\n';

    if (critical.length > 0) {
      output += '### CRITICAL\n';
      critical.forEach(i => {
        const progress = i.completionCriteria.length > 0
          ? Math.round((i.completedCriteria.length / i.completionCriteria.length) * 100)
          : 0;
        output += `- [${progress}%] ${i.title} (#${i.id})\n`;
        output += `  Domain: ${i.inquiryDomain}\n`;
        if (i.completedCriteria.length > 0) {
          output += `  Completed: ${i.completedCriteria.join(', ')}\n`;
        }
        output += `\n`;
      });
    }

    if (high.length > 0) {
      output += '### HIGH PRIORITY\n';
      high.forEach(i => {
        const progress = i.completionCriteria.length > 0
          ? Math.round((i.completedCriteria.length / i.completionCriteria.length) * 100)
          : 0;
        output += `- [${progress}%] ${i.title}\n`;
      });
      output += '\n';
    }

    const focus = this.getFocus();
    if (focus) {
      output += `## CURRENT FOCUS\n> ${focus.title}\n\n`;
    }

    return output;
  }

  // For bootstrap.ts integration
  static generateContext(): string {
    try {
      const tracker = new IntentionTracker();
      return tracker.generateBrief();
    } catch (e) {
      return '\n## Intentions: No active tracking\n';
    }
  }
}

